const{request:request}=require("express"),PRECACHE="precache-v1",RUNTIME="runtime",PRECACHE_URLS=["/upload/index.html","/upload/index.js","/upload/style.min.css","/assets/bootstrap.min.css","/assets/copy.svg","/assets/done.svg","/assets/favicon.svg","/assets/favicon-thin.svg","/upload/manifest.json","/assets/upload-file.svg","/assets/upload-file.png","/assets/Roboto/Roboto-Bold.ttf","/assets/Roboto/Roboto-Regular.ttf"];self.addEventListener("install",e=>{e.waitUntil(caches.open(PRECACHE).then(e=>e.addAll(PRECACHE_URLS)).then(self.skipWaiting()))}),self.addEventListener("activate",e=>{const s=[PRECACHE,RUNTIME];e.waitUntil(caches.keys().then(e=>e.filter(e=>!s.includes(e))).then(e=>Promise.all(e.map(e=>caches.delete(e)))).then(()=>self.clients.claim()))}),self.addEventListener("fetch",e=>{e.request.url.startsWith(self.location.origin)&&e.respondWith(caches.match(e.request).then(s=>"GET"===e.request.method&&s?s:caches.open(RUNTIME).then(s=>fetch(e.request).then(t=>s.put(e.request,t.clone()).then(()=>t)))))});